return items.filter(item => {

  try {

    const ai = item.json.ai || {};

    let score = parseFloat(ai.suitability_score || 0);

    if (isNaN(score)) {
      score = 0;
    }

    // Convert percentages to /10 scale
    if (score > 10) {
      score = score / 10;
    }

    // Convert decimals like 0.7 → 7
    if (score > 0 && score <= 1) {
      score = score * 10;
    }

    const worth = String(
      ai.worth_applying || ""
    ).trim().toLowerCase();

    // Reject explicit NOs
    if (
      ["no", "false", "0"].includes(worth)
    ) {
      return false;
    }

    // Reject low scores
    if (score < 5) {
      return false;
    }

    return true;

  } catch {

    return false;
  }
});

