const incomingJobs = $input.all(0);

// INPUT 1 = existing sheet rows
const existingRows = $input.all(1);

// Build set of existing Job IDs
const existingIds = new Set(
  existingRows.map(row => String(row.json["Job ID"]))
);

// Keep only NEW jobs
