parameters.jsCode:
return items.map(item => {

  let raw = item.json.choices?.[0]?.message?.content || "";

  try {

    raw = raw
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();

    const parsed = JSON.parse(raw);

    // KEEP ORIGINAL DATA
    item.json.ai = parsed;

  } catch (e) {

    item.json.ai = {

      suitability_score: "0%",

      fresher_friendliness: "Low",

      competition_level: "Unknown",

      estimated_interview_probability: "0%",

      difficulty: "Unknown",

      important_skills: [],

      missing_skills: [],

      worth_applying: "NO",

      short_reason: "AI parsing failed."
    };

    item.json.parse_error = raw;
  }

  return item;
});
